**Full component implementation:**
```tsx
export function ChannelBindingCard({
  binding,
  channelName,
  channelIconId,
  channelAdapterType,
  adapterState,
  errorMessage,
  chatDisplayName,
  onEdit,
  onRemove,
}: ChannelBindingCardProps) {
  const [showRemoveConfirm, setShowRemoveConfirm] = useState(false);

  const primaryText = chatDisplayName
    ? `${channelName} \u2014 ${chatDisplayName}`
    : channelName;

  const previewSentence = buildPreviewSentence({
    sessionStrategy: binding.sessionStrategy,
    chatDisplayName,
    channelType: binding.channelType,
  });

  const isRestricted =
    binding.canInitiate === true ||
    binding.canReply === false ||
    binding.canReceive === false;

  const restrictionDetail = isRestricted ? buildRestrictionDetail(binding) : '';

  return (
    <div
      className={cn(
        'group relative rounded-xl border px-4 py-3 transition-colors',
        adapterState === 'error' && 'border-red-500/50 bg-red-500/[0.02]'
      )}
    >
      <div className="flex items-start gap-3">
        {/* Brand icon with status dot overlay */}
        <div className="relative shrink-0">
          <AdapterIcon
            iconId={channelIconId}
            adapterType={channelAdapterType}
            size={32}
          />
          <span
            className={cn(
              'ring-background absolute -right-0.5 -bottom-0.5 size-2.5 rounded-full ring-2',
              STATE_DOT_CLASS[adapterState]
            )}
            role="status"
            aria-label={adapterState === 'connecting' ? 'Connecting' : adapterState.charAt(0).toUpperCase() + adapterState.slice(1)}
          />
        </div>

        {/* Text content */}
        <div className="min-w-0 flex-1">
          <div className="flex items-center gap-2">
            <span className="truncate text-sm font-medium">{primaryText}</span>
          </div>
          {adapterState === 'error' && errorMessage ? (
            <p className="text-xs text-red-600 dark:text-red-400">{errorMessage}</p>
          ) : previewSentence ? (
            <p className="text-muted-foreground truncate text-xs italic">
              {previewSentence}
            </p>
          ) : null}
        </div>

        {/* Restricted pill */}
        {isRestricted && (
          <Tooltip>
            <TooltipTrigger asChild>
              <Badge variant="outline" className="shrink-0 text-xs">
                Restricted
              </Badge>
            </TooltipTrigger>
            <TooltipContent>{restrictionDetail}</TooltipContent>
          </Tooltip>
        )}

        {/* Kebab menu — always visible, not hover-gated */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8 shrink-0"
              aria-label={`Actions for ${channelName}`}
            >
              <MoreHorizontal className="size-4" />
              <span className="sr-only">Actions</span>
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={onEdit}>Edit</DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => setShowRemoveConfirm(true)}
              className="text-destructive focus:text-destructive"
            >
              Remove
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>

      {/* Remove confirmation */}
      <AlertDialog open={showRemoveConfirm} onOpenChange={setShowRemoveConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remove channel binding</AlertDialogTitle>
            <AlertDialogDescription>
              Remove the binding to {channelName}? The agent will no longer
              receive messages from this channel.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => {
                onRemove();
                setShowRemoveConfirm(false);
              }}
              className="bg-red-600 hover:bg-red-700"
            >
              Remove
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}
```

