Create the `BoundChannelRow` component that wraps `ChannelBindingCard` with per-row `useObservedChats` resolution, then update `ChannelsTab` to use it and to pass the new card props.

**File to create:** `apps/client/src/layers/features/agent-settings/ui/BoundChannelRow.tsx`

```tsx
import { useObservedChats } from '@/layers/entities/relay';
import type { AdapterBinding } from '@dorkos/shared/relay-schemas';
import { ChannelBindingCard } from './ChannelBindingCard';

interface BoundChannelRowProps {
  /** The binding to render. */
  binding: AdapterBinding;
  /** Display name of the channel from catalog. */
  channelName: string;
  /** Adapter icon identifier for brand logo resolution. */
  channelIconId?: string;
  /** Adapter type — fallback for icon resolution. */
  channelAdapterType: string;
  /** Current adapter connection state. */
  adapterState: 'connected' | 'disconnected' | 'error' | 'connecting';
  /** Error message to display in error state. */
  errorMessage?: string;
  /** Called when the user clicks Edit in the kebab menu. */
  onEdit: () => void;
  /** Called when the user confirms removal. */
  onRemove: () => void;
}

/**
 * Thin wrapper around ChannelBindingCard that resolves a binding's
 * raw chatId to a friendly display name via useObservedChats.
 *
 * This exists as a separate component so each row can safely call
 * the per-adapter chat hook without violating the rules-of-hooks.
 */
export function BoundChannelRow({ binding, ...rest }: BoundChannelRowProps) {
  const { data: observedChats = [] } = useObservedChats(binding.adapterId);
  const chat = binding.chatId
    ? observedChats.find((c) => c.chatId === binding.chatId)
    : undefined;
  const chatDisplayName =
    chat?.displayName ?? (binding.chatId ? `#${binding.chatId.slice(-4)}` : undefined);

  return (
    <ChannelBindingCard
      binding={binding}
      chatDisplayName={chatDisplayName}
      {...rest}
    />
  );
}
```

**File to modify:** `apps/client/src/layers/features/agent-settings/ui/ChannelsTab.tsx`

Changes to the data flow:

1. **Extend `AdapterDisplay` interface** to carry `iconId` and `adapterType`:
```ts
interface AdapterDisplay {
  state: 'connected' | 'disconnected' | 'error' | 'connecting';
  name: string;
  iconId?: string;
  adapterType: string;
  errorMessage?: string;
}
```

2. **Update `adapterDisplayByInstanceId` memo** to surface transient states as `'connecting'` instead of normalizing to `'disconnected'`, and to copy `iconId` and `adapterType` from each `entry.manifest`:
```ts
const adapterDisplayByInstanceId = useMemo(() => {
  const map = new Map<string, AdapterDisplay>();
  for (const entry of externalCatalog) {
    for (const inst of entry.instances) {
      const raw = inst.status.state;
      const state: AdapterDisplay['state'] =
        raw === 'connected' || raw === 'error'
          ? raw
          : raw === 'starting' || raw === 'stopping' || raw === 'reconnecting'
            ? 'connecting'
            : 'disconnected';
      map.set(inst.id, {
        state,
        name: inst.status.displayName ?? entry.manifest.displayName,
        iconId: entry.manifest.iconId,
        adapterType: entry.manifest.type,
        errorMessage: inst.status.lastError ?? undefined,
      });
    }
  }
  return map;
}, [externalCatalog]);
```

3. **Update `resolveAdapterDisplay` fallback** to include `adapterType`:
```ts
const resolveAdapterDisplay = useCallback(
  (adapterId: string): AdapterDisplay =>
    adapterDisplayByInstanceId.get(adapterId) ?? {
      state: 'disconnected',
      name: adapterId,
      adapterType: 'unknown',
    },
  [adapterDisplayByInstanceId]
);
```

4. **Replace `<ChannelBindingCard>` with `<BoundChannelRow>`** in the binding list map:
